const JSZip = require('jszip');

const results = [];

for (const item of $input.all()) {
  try {
    // Buscar binario ZIP en los adjuntos
    const binaries = item.binary || {};
    let zipBinary = null;
    let zipKey = null;

    for (const [key, bin] of Object.entries(binaries)) {
      if (bin.fileName && bin.fileName.toLowerCase().endsWith('.zip')) {
        zipBinary = bin;
        zipKey = key;
        break;
      }
    }

    if (!zipBinary) {
      // Tal vez el adjunto es XML o PDF directo
      results.push({ json: { ...item.json, error: 'No ZIP encontrado' } });
      continue;
    }

    // Obtener buffer del ZIP
    const zipBuffer = await this.helpers.getBinaryDataBuffer(item, zipKey);
    const zip = await JSZip.loadAsync(zipBuffer);

    let xmlContent = null;
    let pdfFileName = null;
    let xmlFileName = null;

    for (const [filename, file] of Object.entries(zip.files)) {
      if (filename.startsWith('__MACOSX')) continue;
      if (filename.toLowerCase().endsWith('.xml')) {
        xmlContent = await file.async('text');
        xmlFileName = filename;
      }
      if (filename.toLowerCase().endsWith('.pdf')) {
        pdfFileName = filename;
      }
    }

    if (!xmlContent) {
      results.push({ json: { ...item.json, error: 'No XML en ZIP' } });
      continue;
    }

    // Detectar formato
    const isAttached = xmlContent.includes('AttachedDocument');

    let nit = 'N/A', razonSocial = 'N/A', numFactura = 'N/A';
    let fecha = 'N/A', total = 0, descripcion = 'N/A';

    if (isAttached) {
      const idMatch = xmlContent.match(/<cbc:ID>([^<]+)</);
      if (idMatch) numFactura = idMatch[1].trim();

      const dateMatch = xmlContent.match(/<cbc:IssueDate>([^<]+)</);
      if (dateMatch) fecha = dateMatch[1].trim();

      const senderMatch = xmlContent.match(/<cac:SenderParty>([\s\S]*?)<\/cac:SenderParty>/);
      if (senderMatch) {
        const s = senderMatch[1];
        const nitM = s.match(/<cbc:CompanyID[^>]*>([^<]+)</);
        if (nitM) nit = nitM[1].trim();
        const rsM = s.match(/<cbc:RegistrationName>([^<]+)</);
        if (rsM) razonSocial = rsM[1].trim();
      }

      // Factura embebida
      const descMatch = xmlContent.match(/<cbc:Description>([\s\S]*?)<\/cbc:Description>/);
      if (descMatch) {
        let embedded = descMatch[1];
        embedded = embedded.replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&');

        const payM = embedded.match(/<cbc:PayableAmount[^>]*>([^<]+)</);
        if (payM) total = parseFloat(payM[1]) || 0;

        const itemDescM = embedded.match(/<cbc:Description>([^<]{1,200})</);
        if (itemDescM) descripcion = itemDescM[1].trim();
      }
    } else {
      const idMatch = xmlContent.match(/<cbc:ID>([^<]+)</);
      if (idMatch) numFactura = idMatch[1].trim();

      const dateMatch = xmlContent.match(/<cbc:IssueDate>([^<]+)</);
      if (dateMatch) fecha = dateMatch[1].trim();

      const supMatch = xmlContent.match(/<cac:AccountingSupplierParty>([\s\S]*?)<\/cac:AccountingSupplierParty>/);
      if (supMatch) {
        const s = supMatch[1];
        const nitM = s.match(/<cbc:CompanyID[^>]*>([^<]+)</);
        if (nitM) nit = nitM[1].trim();
        const rsM = s.match(/<cbc:RegistrationName>([^<]+)</);
        if (rsM) razonSocial = rsM[1].trim();
      }

      const payM = xmlContent.match(/<cbc:PayableAmount[^>]*>([^<]+)</);
      if (payM) total = parseFloat(payM[1]) || 0;

      const itemDescM = xmlContent.match(/<cbc:Description>([^<]{1,200})</);
      if (itemDescM) descripcion = itemDescM[1].trim();
    }

    results.push({
      json: {
        nit_emisor: nit,
        razon_social: razonSocial,
        numero_factura: numFactura,
        fecha_emision: fecha,
        valor_total: total,
        descripcion: descripcion,
        archivo_pdf: pdfFileName || 'N/A',
        archivo_xml: xmlFileName || 'N/A',
        email_from: item.json.from?.text || item.json.from || '',
        email_date: item.json.date || ''
      }
    });
  } catch (error) {
    results.push({
      json: { error: error.message, email_subject: item.json.subject || '' }
    });
  }
}

return results;
